fn solve(nums: Array(Int64)): Array(Int64) {
    let n = nums.len
    if n == 0 {
        return Array(Int64)()
    }
    if n == 1 {
        return [nums[0]]
    }

    // 1. Calculate Prefix Maximums (PMax[i] = max(nums[0]...nums[i]))
    let pmax = Array(Int64) { 0 }
    pmax[0] = nums[0]
    for i in 1...n {
        pmax[i] = pmax[i-1].max(nums[i])
    }

    // 2. Calculate Suffix Maximums (SMax[i] = max(nums[i]...nums[n-1]))
    let smax = Array(Int64) { 0 }
    smax[n-1] = nums[n-1]
    for i in (0..n-2).reverse() {
        smax[i] = smax[i+1].max(nums[i])
    }

    // 3. Check validity
    var result = Array(Int64)()

    for i in 0..<n {
        let is_valid = false

        // Always valid if it's the first or last element
        if i == 0 || i == n - 1 {
            is_valid = true
        } else {
            // Check Left: nums[i] > max(nums[0]...nums[i-1])
            // max(nums[0]...nums[i-1]) is pmax[i-1]
            let greater_than_left = nums[i] > pmax[i-1]

            // Check Right: nums[i] > max(nums[i+1]...nums[n-1])
            // max(nums[i+1]...nums[n-1]) is smax[i+1]
            let greater_than_right = nums[i] > smax[i+1]

            if greater_than_left || greater_than_right {
                is_valid = true
            }
        }

        if is_valid {
            result.push(nums[i])
        }
    }

    return result
}

